  ('heelevel3-d0d1b9a2-moex-00212', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於5月24日宣告，將於8月25日發放乙公司股票1,000股給股東，宣告日乙公司股票價格 為每股$12，甲公司取得乙公司股票的成本為每股$11，並分類為「透過損益按公允價值衡量 之金融資產」。若乙公司股票於8月25日為每股$14，則甲公司宣告與發放財產股利及金融資產 價值變動，對甲公司當年度權益的總影響為何？（假設不考慮所得稅之影響）', '["減少$11,000", "減少$12,000", "減少$13,000", "減少$14,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "2b5ab581203c", "answer_pdf_sha1": "5685b74c595b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00213', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年1月1日，平價發行面額$1,000的3年期可轉換債券2,000張，名目利率6%，年底 付息，每張債券可於到期日前，轉換為25股面額$10的普通股，發行當日，不附轉換權的債券 其市場利率為9%。若甲公司於X2年1月1日以$1,180,000買回一半流通在外的可轉換公司債， 其中$1,100,000屬於負債組成部分的對價，則X2年1月1日買回可轉換公司債之交易，對甲公 司權益總額有何影響？', '["減少$75,939", "減少$80,000", "減少$156,834", "減少$232,773"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "2b5ab581203c", "answer_pdf_sha1": "5685b74c595b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00214', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司X1年1月1日流通在外普通股1,000,000股，每股面額$10，3月1日發放股票股利10%，4 月1日現金增資500,000股，每股認購價格為$24.4，3月31日市價為每股$28。8月1日股票分割， 每股分割成二股，10月1日購入庫藏股票400,000股，至12月31日尚未出售，亦未註銷。若X1 年12月31日流通在外股數為2,800,000股，則甲公司X1年計算基本每股盈餘之普通股加權平均 流通在外股數為何？', '["2,053,189股", "2,838,315股", "2,850,000股", "2,873,045股"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "2b5ab581203c", "answer_pdf_sha1": "5685b74c595b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL)
